-
-    for (value) |byte| {
-        if (byte >= 0x20 and byte < 0x7f and byte != '\'' and byte != '\\') {
-            try result.append(byte);
-        } else if (byte == '\\') {
-            try result.appendSlice("\\\\");
-        } else if (byte == '\'') {
-            try result.appendSlice("\\'");
