+// Tests
+// ============================================================================
+
+test "hash function" {
+    const h1 = hash_builtin("hello");
+    const h2 = hash_builtin("hello");
+    const h3 = hash_builtin("world");
+
+    try std.testing.expectEqual(h1, h2);
+    try std.testing.expect(h1 != h3);
+}

