+
+test "load attr specialization" {
+    var ctx = SpecializationContext{
+        .ip = 0,
+        .opcode = 106, // LOAD_ATTR
+        .oparg = 0,
+        .cache = null,
+        .obj_type = .module,
+    };
+
+    const result = specializeLoadAttr(&ctx);
+    try std.testing.expectEqual(SpecializedOp.LOAD_ATTR_MODULE, result);
